        );
INSERT INTO messages VALUES(1,'8b839829-789e-4bdc-b1ae-b092003847d5','5b218284-7761-4ca0-ab01-82d4c97cb67c','user','What is the capital of Australia?',NULL,'2026-06-07T13:11:25');
INSERT INTO messages VALUES(2,'8b839829-789e-4bdc-b1ae-b092003847d5','5b218284-7761-4ca0-ab01-82d4c97cb67c','assistant','The capital of Australia is Canberra. It was purpose-built as the capital city and is located in the Australian Capital Territory (ACT). Canberra was chosen as a compromise between rivals Sydney and Melbourne, and was designed by American architects Walter Burley Griffin and Marion Mahoney Griffin. The city was established in the early 20th century and officially became the capital in 1927.',NULL,'2026-06-07T13:11:37');
INSERT INTO messages VALUES(3,'8b839829-789e-4bdc-b1ae-b092003847d5','00508819-6371-4143-b218-d9a0203d389a','user','Latest news on AI regulation',NULL,'2026-06-07T13:12:33');
INSERT INTO messages VALUES(4,'8b839829-789e-4bdc-b1ae-b092003847d5','00508819-6371-4143-b218-d9a0203d389a','assistant',unistr('Here is a comprehensive overview of the latest AI regulation news as of June 2026, broken down by region and key developments:\u000a\u000a---\u000a\u000a## 🇺🇸 United States: Federal Level\u000a\u000a### New White House Executive Order (June 2, 2026)\u000aThe U.S. continues to pursue an innovation-first approach, with the administration stating it "refuse[s] to stifle this innovation with overly burdensome regulation" and claiming to have "unleashed tremendous technological growth and economic investment in AI by slashing the bureaucratic constraints that the prior administration placed on America''s AI developers and researchers."\u000a\u000aHowever, the order also acknowledges that advanced AI capabilities "introduce new national security considerations that require coordinated action across executive departments and agencies," and the administration pledges to "work closely with industry to ensure that the best and most secure technology is deployed rapidly to confront any and all threats."\u000a\u000a### White House National Policy Framework (March 2026)\u000aOn March 20, 2026, the White House released a four-page blueprint directing Congress to adopt a unified federal approach to AI governance. The framework includes six broad objectives: protecting children online, safeguarding against AI-related harms, respecting intellectual property rights, preventing AI-driven censorship, promoting innovation, and developing an AI-ready workforce. Most importantly, it calls for **federal preemption of state AI laws**, arguing against a "patchwork" of state laws as an obstacle to innovation.\u000a\u000aHowever, the framework also leaves wide regulatory gaps regarding bias standards, adult data privacy protections, and transparency mandates, possibly allowing for state and local governance in those areas.\u000a\u000a### Federal Legislation Introduced\u000aThe **Protecting Consumers From Deceptive AI Act** was introduced on April 23, 2026. The bill would direct NIST to develop guidelines for watermarking, digital fingerprinting, and provenance metadata for AI-generated audio and visual content, as well as support labeling standards for AI-modified content on platforms and develop frameworks for identifying AI-generated text.\u000a\u000a### AI Litigation Task Force\u000aThe December 2025 Executive Order directed the Attorney General to establish an AI litigation task force to challenge state AI laws deemed inconsistent with federal policy, including on the grounds of unconstitutional regulation of interstate commerce and federal preemption. It also calls for an evaluation of state AI laws, including those that compel disclosures or alter model outputs in ways that may raise constitutional concerns.\u000a\u000a---\u000a\u000a## 🏛️ United States: State Level\u000a\u000a### California\u000a**CA AB 2013**, which came into effect on January 1, 2026, requires developers of generative AI systems to post documentation on their websites about the data used to train their systems. **CA SB 942**, also effective January 1, 2026, requires covered providers to include a latent disclosure in AI-generated images, videos, and audio content regarding the provenance of the content.\u000a\u000aMost provisions of California''s **Transparency in Frontier AI Act (CA SB 53)** became effective on January 1, 2026. The statute requires large frontier AI model developers to create and publish an AI safety and security framework, report certain safety incidents, and provide transparency disclosures related to frontier AI models'' risk assessment and use.\u000a\u000a### New York\u000aNew York Gov. Kathy Hochul signed the **Responsible AI Safety and Education (RAISE) Act** in December 2025, with amendments signed on March 27, 2026, shifting it toward a transparency and reporting-based framework — including model-level obligations on training, deployment, safety protocols, and incidents, and a shift away from deployment restrictions that had earlier prohibited models posing an "unreasonable risk of critical harm."\u000a\u000aIn March 2026, New York amended the RAISE Act to more closely mirror California''s CA SB 53, which could potentially ease some multistate compliance challenges for large frontier AI model developers.\u000a\u000a### Colorado\u000aColorado''s SB 205 has been subject to significant debate and criticism from the tech industry. Concerns prompted a special legislative session that postponed enforcement from February 1, 2026, to June 30, 2026. Colorado is now considering a more substantive revision — a March 2026 working group draft would repeal and reenact the law with a focus on automated decision-making technology (ADMT), resetting the effective date to January 1, 2027.\u000a\u000a### Texas\u000aTexas''s **Responsible Artificial Intelligence Governance Act** has taken effect, incorporating privacy-focused provisions and imposing disclosure and governance requirements related to transparency, automated decision-making, and how personal data can be used to train or operate AI systems.\u000a\u000a### CCPA Automated Decision-Making Rules\u000aUnder new CCPA regulations, businesses that use "automated decision-making technology" (ADMT) to make "significant decisions" about consumers — such as those involving financial services, housing, education, employment, or healthcare — must provide pre-use notice, the ability to opt out, and access to information about the ADMT use. These regulations went into effect on January 1, 2026, with full compliance required by January 1, 2027.\u000a\u000a---\u000a\u000a## 🇪🇺 European Union: EU AI Act Updates (May 2026)\u000a\u000aOn May 7, 2026, negotiators from the Council of the EU, the European Parliament, and the European Commission reached a provisional agreement on amendments to the AI Act, with final approval anticipated in June and publication expected in July.\u000a\u000aKey changes include:\u000a- **Delayed timelines:** For high-risk AI systems (use-based), obligations are postponed from August 2026 to December 2027 (a 16-month deferral). For product-regulated high-risk AI (including medical devices and lifts), obligations are postponed from August 2027 to August 2028.\u000a- **New prohibitions:** The most visible changes include two new prohibited AI practices: the use of AI systems to generate or manipulate non-consensual intimate material and child sexual abuse material (CSAM), with the prohibition taking effect on December 2, 2026.\u000a- **Regulatory sandboxes:** The obligation for EU Member States to establish at least one national regulatory sandbox is postponed from August 2026 to August 2027.\u000a\u000a---\u000a\u000a## ⚖️ Key Tensions & Outlook\u000a\u000aThe fight over who will shape AI regulation in the United States is becoming sharper, with the Trump Administration pressing for a single, national framework that limits fragmented state-by-state rules.\u000a\u000aStates may contest federal primacy, leading to constitutional challenges over preemption and states'' rights. For now, businesses must continue to comply with existing state requirements unless and until the federal preemption issue is clarified.\u000a\u000aGlobally, AI regulation is moving from theory to enforcement. Legislators are no longer debating *whether* AI needs oversight — they are defining who is responsible, when risk assessments are required, what must be disclosed, and how enforcement will work in practice.'),'[{"url": "https://www.whitehouse.gov/presidential-actions/2026/06/promoting-advanced-artificial-intelligence-innovation-and-security/", "title": "Promoting Advanced Artificial Intelligence Innovation and Security \u2013 The White House"}, {"url": "https://www.vorys.com/publication-battle-for-ai-governance-white-houses-plan-to-centralize-ai-regulation-and-states-continuous-opposition", "title": "Battle for AI Governance: White House\u2019s Plan to Centralize AI Regulation and States\u2019 Continuous Opposition"}, {"url": "https://www.wsgr.com/en/insights/recent-ai-regulatory-developments-in-the-united-states.html", "title": "Recent AI Regulatory Developments in the United States | Wilson Sonsini"}, {"url": "https://www.kslaw.com/news-and-insights/new-state-ai-laws-are-effective-on-january-1-2026-but-a-new-executive-order-signals-disruption", "title": "New State AI Laws are Effective on January 1, 2026, But a New Executive Order Signals Disruption - King & Spalding"}, {"url": "https://www.cooley.com/news/insight/2026/2026-04-24-state-ai-laws-where-are-they-now", "title": "State AI Laws \u2013 Where Are They Now? // Cooley // Global Law Firm"}, {"url": "https://www.globalpolicywatch.com/2026/05/eu-ai-act-update-timeline-relief-targeted-simplification-and-new-prohibitions/", "title": "EU AI Act Update: Timeline Relief, Targeted Simplification, and New Prohibitions"}, {"url": "https://www.onetrust.com/blog/where-ai-regulation-is-heading-in-2026-a-global-outlook/", "title": "Where AI Regulation is Heading in 2026: A Global Outlook | Blog | OneTrust"}, {"url": "https://www.gunder.com/en/news-insights/insights/2026-ai-laws-update-key-regulations-and-practical-guidance", "title": "2026 AI Laws Update: Key Regulations and Practical Guidance | Gunderson Dettmer Stough Villeneuve Franklin & Hachigian, LLP"}]','2026-06-07T13:12:38');
